// Extrai e valida os dados vindos do app React
const body = $input.first().json.body;

const produto = body.productName || 'Não informado';
const custoBase = parseFloat(body.baseUnitCost) || 0;
const precoSugerido = parseFloat(body.suggestedPrice) || 0;
const precoManual = parseFloat(body.customPrice) || 0;
const precoFinal = precoManual > 0 ? precoManual : precoSugerido;
const margemLiquida = parseFloat(body.netMarginPct) || 0;
const canal = body.channel === 'ifood' ? 'iFood (25%)' : 'Venda Direta (0%)';
const margem = parseFloat(body.margin) || 30;
const imposto = parseFloat(body.tax) || 6;

// Classificação de saúde da margem
let saudeLabel = '';
if (margemLiquida >= 25) saudeLabel = '✅ Saudável';
else if (margemLiquida >= 11) saudeLabel = '⚠️ Alerta';
else saudeLabel = '🚨 Perigosa';

const now = new Date();
const dataHora = now.toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

return [{
  json: {
    dataHora,
    produto,
    custoBase: custoBase.toFixed(2),
    precoFinal: precoFinal.toFixed(2),
    margemLiquida: margemLiquida.toFixed(1),
    saudeLabel,
    canal,
    margemDesejada: margem,
    impostoNF: imposto,
    alertar: margemLiquida < 10
  }
}];
